from microcoapy import CoapServer, CoapResource
import machine

# Define sensor and actuator values
temp = 25
light = 50

# Create CoAP server
server = CoapServer()

# Define sensor resource
class TempResource(CoapResource):
    def get(self, request):
        return b'{}'.format(temp)

server.add_resource('/sensors/temp', TempResource())

# Define actuator resource
class LightResource(CoapResource):
    def put(self, request):
        global light
        light = int(request.payload)
        return b'OK'

server.add_resource('/actuators/light', LightResource())

# Run CoAP server
server.run()